import org.junit.jupiter.api.*;
import org.junit.jupiter.params.ParameterizedTest;
import org.junit.jupiter.params.provider.*;
import static org.junit.jupiter.api.Assertions.*;

class CalculatorTest {

    static class Calculator {
        int add(int a, int b) { return a + b; }
        int divide(int a, int b) {
            if (b == 0) throw new ArithmeticException("Division by zero");
            return a / b;
        }
        double average(int[] nums) {
            if (nums.length == 0) throw new IllegalArgumentException("Empty array");
            int sum = 0;
            for (int n : nums) sum += n;
            return (double) sum / nums.length;
        }
    }

    Calculator calc;

    @BeforeEach
    void setUp() {
        calc = new Calculator(); // fresh instance per test
    }

    @Test
    @DisplayName("Addition: 2 + 3 = 5")
    void testAdd() {
        assertEquals(5, calc.add(2, 3));
        assertEquals(0, calc.add(-1, 1));
        assertEquals(-5, calc.add(-2, -3));
    }

    @Test
    @DisplayName("Division by zero throws ArithmeticException")
    void testDivideByZero() {
        ArithmeticException ex = assertThrows(
            ArithmeticException.class,
            () -> calc.divide(10, 0)
        );
        assertEquals("Division by zero", ex.getMessage());
    }

    @Test
    @DisplayName("Multiple assertions grouped — all reported on failure")
    void testGrouped() {
        assertAll("add edge cases",
            () -> assertEquals(Integer.MAX_VALUE, calc.add(Integer.MAX_VALUE, 0)),
            () -> assertEquals(0, calc.add(0, 0)),
            () -> assertEquals(-10, calc.add(-5, -5))
        );
    }

    @ParameterizedTest
    @CsvSource({
        "6, 2, 3",  // 6/2=3
        "10, 5, 2", // 10/5=2
        "7, 1, 7"   // 7/1=7
    })
    @DisplayName("Division parameterized")
    void testDivide(int a, int b, int expected) {
        assertEquals(expected, calc.divide(a, b));
    }

    @ParameterizedTest
    @ValueSource(ints = {1, 2, 3, 100, -5})
    @DisplayName("Add with zero always returns same number")
    void testAddZeroIdentity(int n) {
        assertEquals(n, calc.add(n, 0));
    }

    @Test
    void testAverageThrowsOnEmpty() {
        assertThrows(IllegalArgumentException.class, () -> calc.average(new int[]{}));
    }
}

import org.junit.jupiter.api.*;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.*;
import org.mockito.junit.jupiter.MockitoExtension;
import static org.mockito.Mockito.*;
import static org.junit.jupiter.api.Assertions.*;
import java.util.*;

@ExtendWith(MockitoExtension.class)
class UserServiceTest {

    // Interfaces to mock
    interface UserRepository { Optional<User> findById(long id); void save(User u); }
    interface EmailService { void sendWelcome(String email); }
    record User(long id, String name, String email, boolean active) {}

    // System Under Test (SUT)
    static class UserService {
        private final UserRepository repo;
        private final EmailService emailSvc;
        UserService(UserRepository r, EmailService e) { repo = r; emailSvc = e; }

        User activateUser(long userId) {
            User user = repo.findById(userId)
                .orElseThrow(() -> new NoSuchElementException("User not found: " + userId));
            if (user.active()) throw new IllegalStateException("User already active");
            User activated = new User(user.id(), user.name(), user.email(), true);
            repo.save(activated);
            emailSvc.sendWelcome(user.email());
            return activated;
        }
    }

    @Mock UserRepository userRepo;
    @Mock EmailService emailService;
    @InjectMocks UserService userService; // auto-injects @Mocks
    @Captor ArgumentCaptor<User> userCaptor;
    @Captor ArgumentCaptor<String> emailCaptor;

    @Test
    @DisplayName("activateUser: saves activated user and sends welcome email")
    void testActivateUser() {
        // Arrange
        User inactive = new User(1L, "Alice", "alice@test.com", false);
        when(userRepo.findById(1L)).thenReturn(Optional.of(inactive));

        // Act
        User result = userService.activateUser(1L);

        // Assert
        assertTrue(result.active());
        assertEquals("alice@test.com", result.email());

        // Verify interactions
        verify(userRepo).save(userCaptor.capture());
        assertTrue(userCaptor.getValue().active());

        verify(emailService).sendWelcome(emailCaptor.capture());
        assertEquals("alice@test.com", emailCaptor.getValue());
    }

    @Test
    @DisplayName("activateUser: throws when user not found")
    void testUserNotFound() {
        when(userRepo.findById(99L)).thenReturn(Optional.empty());
        assertThrows(NoSuchElementException.class, () -> userService.activateUser(99L));
        verify(emailService, never()).sendWelcome(any()); // email never sent
    }

    @Test
    @DisplayName("activateUser: throws when user already active")
    void testAlreadyActive() {
        User active = new User(2L, "Bob", "bob@test.com", true);
        when(userRepo.findById(2L)).thenReturn(Optional.of(active));
        assertThrows(IllegalStateException.class, () -> userService.activateUser(2L));
        verify(userRepo, never()).save(any()); // not saved if already active
    }
}

