import org.junit.jupiter.api.*;
import static org.junit.jupiter.api.Assertions.*;

class BankAccountTest {
    static class BankAccount {
        private double balance = 0;
        public void deposit(double amount) {
            if (amount <= 0) throw new IllegalArgumentException("Amount must be positive");
            balance += amount;
        }
        public void withdraw(double amount) {
            if (amount > balance) throw new IllegalStateException("Insufficient funds");
            balance -= amount;
        }
        public double getBalance() { return balance; }
    }

    BankAccount account;
    @BeforeEach void setUp() { account = new BankAccount(); }

    @Test @DisplayName("Initial balance is zero")
    void testInitialBalance() { assertEquals(0.0, account.getBalance()); }

    @Test @DisplayName("Deposit increases balance")
    void testDeposit() {
        account.deposit(100.0);
        account.deposit(50.0);
        assertEquals(150.0, account.getBalance());
    }

    @Test @DisplayName("Withdraw decreases balance")
    void testWithdraw() {
        account.deposit(200.0);
        account.withdraw(75.0);
        assertEquals(125.0, account.getBalance());
    }

    @Test @DisplayName("Overdraft throws IllegalStateException")
    void testOverdraft() {
        account.deposit(50.0);
        assertThrows(IllegalStateException.class, () -> account.withdraw(100.0));
        assertEquals(50.0, account.getBalance()); // balance unchanged
    }

    @Test @DisplayName("Negative deposit throws IllegalArgumentException")
    void testNegativeDeposit() {
        assertThrows(IllegalArgumentException.class, () -> account.deposit(-10.0));
    }
}

