import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.*;
import org.mockito.junit.jupiter.MockitoExtension;
import static org.mockito.Mockito.*;
import static org.junit.jupiter.api.Assertions.*;

@ExtendWith(MockitoExtension.class)
class UserRegistrationServiceTest {
    interface UserRepository { void save(String username); }
    interface EmailService { void sendVerification(String email); }
    static class UserRegistrationService {
        private final UserRepository repo;
        private final EmailService email;
        UserRegistrationService(UserRepository r, EmailService e) { repo=r; email=e; }
        void register(String username, String emailAddr) {
            repo.save(username); email.sendVerification(emailAddr);
        }
    }

    @Mock UserRepository repo;
    @Mock EmailService emailSvc;
    @InjectMocks UserRegistrationService service;
    @Captor ArgumentCaptor<String> emailCaptor;

    @Test
    @org.junit.jupiter.api.DisplayName("Saves user and sends verification email")
    void testSuccessfulRegistration() {
        service.register("alice", "alice@test.com");
        verify(repo, times(1)).save("alice");
        verify(emailSvc).sendVerification(emailCaptor.capture());
        assertEquals("alice@test.com", emailCaptor.getValue());
    }

    @Test
    @org.junit.jupiter.api.DisplayName("Email not sent when save fails")
    void testEmailNotSentOnSaveFailure() {
        doThrow(new RuntimeException("DB error")).when(repo).save(any());
        assertThrows(RuntimeException.class, () -> service.register("bob", "bob@test.com"));
        verify(emailSvc, never()).sendVerification(any());
    }
}

