import org.junit.jupiter.params.ParameterizedTest;
import org.junit.jupiter.params.provider.*;
import static org.junit.jupiter.api.Assertions.*;

class EmailValidatorTest {
    static boolean validate(String email) {
        if (email == null || email.isBlank()) return false;
        return email.matches("^[\\w.+-]+@[\\w-]+\\.[\\w.]+$");
    }

    @ParameterizedTest
    @ValueSource(strings = {"alice@example.com", "bob@test.co.uk", "x+tag@domain.org"})
    void testValidEmails(String email) {
        assertTrue(validate(email), email + " should be valid");
    }

    @ParameterizedTest
    @ValueSource(strings = {"invalid", "@nodomain", "missing@", "no-at-sign"})
    void testInvalidEmails(String email) {
        assertFalse(validate(email), email + " should be invalid");
    }

    @ParameterizedTest
    @NullAndEmptySource
    void testNullAndEmpty(String email) {
        assertFalse(validate(email));
    }
}
